package macros

import scala.quoted.*

// ---------------------------------------------------------------------------
// Instrumentation macros
//
// These macros capture information that is only available at compile time
// (source file, line number, expression text) and embed it into the
// generated bytecode, giving zero-overhead logging that no runtime approach
// can replicate exactly.
// ---------------------------------------------------------------------------
object Logging:

  // ── log ──────────────────────────────────────────────────────────────────

  // The macro stringifies the *source text* of the expression (not just its
  // value) and records the exact file name and line number — capabilities
  // that require the Quotes/Reflect Position API.
  /**
   * Evaluates `expr`, prints its source text and resulting value annotated
   * with the call-site file and line number, then returns the value unchanged.
   */
  inline def log[A](inline expr: A): A = ${ logImpl('expr) }

  def logImpl[A: Type](expr: Expr[A])(using Quotes): Expr[A] =
    import quotes.reflect.*
    val pos     = expr.asTerm.pos
    val srcText = Expr(expr.show)               // source representation of expr
    val file    = Expr(pos.sourceFile.name)
    val line    = Expr(pos.startLine + 1)       // 1-based
    '{
      val result = $expr
      println(s"[LOG ${$file}:${$line}] ${$srcText} => $result")
      result
    }

  // ── time ─────────────────────────────────────────────────────────────────

  /** Measures the wall-clock time of `block` and prints it under `label`. */
  inline def time[A](inline label: String)(inline block: A): A =
    ${ timeImpl('label, 'block) }

  def timeImpl[A: Type](label: Expr[String], block: Expr[A])(using Quotes): Expr[A] =
    '{
      val t0     = System.nanoTime()
      val result = $block
      val ms     = (System.nanoTime() - t0) / 1_000_000.0
      println(f"[TIME] ${$label}: $ms%.3f ms")
      result
    }

  // ── trace ────────────────────────────────────────────────────────────────

  /**
   * Evaluates `expr`, prints a named trace entry with the source text of the
   * expression and its value, then returns the value.
   *
   * Usage:  val result = trace("step1", heavyComputation(x, y))
   */
  inline def trace[A](inline name: String, inline expr: A): A =
    ${ traceImpl('name, 'expr) }

  def traceImpl[A: Type](name: Expr[String], expr: Expr[A])(using Quotes): Expr[A] =
    import quotes.reflect.*
    val pos     = expr.asTerm.pos
    val srcText = Expr(expr.show)
    val line    = Expr(pos.startLine + 1)
    '{
      val result = $expr
      println(s"[TRACE:${$line}] ${$name} | ${$srcText} = $result")
      result
    }

  // ── logIf ────────────────────────────────────────────────────────────────

  /**
   * Logs the expression only when the compile-time flag is true.
   * Passing `false` generates *no code at all* — not even the println.
   * This shows that macros can be used for dead-code elimination.
   */
  inline def logIf[A](inline enabled: Boolean)(inline expr: A): A =
    ${ logIfImpl('enabled, 'expr) }

  def logIfImpl[A: Type](enabled: Expr[Boolean], expr: Expr[A])(using Quotes): Expr[A] =
    import quotes.reflect.*
    enabled.value match
      case Some(true)  => logImpl(expr)   // reuse log implementation
      case Some(false) => expr            // generate plain expression, zero overhead
      case None =>
        report.errorAndAbort("logIf requires a compile-time Boolean literal")

  // ── benchmark ────────────────────────────────────────────────────────────

  /**
   * Runs `block` `iterations` times (compile-time constant), records each
   * run, then prints min/max/avg statistics.
   * The loop is unrolled if `iterations` is small; for larger values the
   * compiler folds it into a regular loop in bytecode.
   */
  inline def benchmark[A](inline label: String, inline iterations: Int)(inline block: A): A =
    ${ benchmarkImpl('label, 'iterations, 'block) }

  def benchmarkImpl[A: Type](
      label: Expr[String],
      iterations: Expr[Int],
      block: Expr[A]
  )(using Quotes): Expr[A] =
    import quotes.reflect.*
    iterations.value match
      case None =>
        report.errorAndAbort("benchmark requires an integer literal for iterations")
      case Some(n) if n <= 0 =>
        report.errorAndAbort(s"benchmark iterations must be > 0, got $n")
      case Some(n) =>
        val nExpr = Expr(n)
        '{
          val times = new Array[Long]($nExpr)
          var last  = $block   // warm-up
          var i     = 0
          while i < $nExpr do
            val t0  = System.nanoTime()
            last    = $block
            times(i) = System.nanoTime() - t0
            i += 1
          val min  = times.min  / 1_000_000.0
          val max  = times.max  / 1_000_000.0
          val avg  = times.sum.toDouble / $nExpr / 1_000_000.0
          println(f"[BENCH] ${$label} (${$nExpr} runs): min=$min%.3f ms  max=$max%.3f ms  avg=$avg%.3f ms")
          last
        }
